// Route: "/focus" → FocusSession (nav hidden on this screen)
import type { BlockedApp } from '@/src/components/blocked/BlockedAppCard';
import { UnlockDialog } from '@/src/components/blocked/UnlockDialog';
import {
  FocusTimer,
  SessionControls,
  SessionStats,
  SubjectStats,
  TimeAdjuster,
  useFocusStore,
} from '@/src/components/focus';
import { COLORS } from '@/src/constants/colors';
import { RADIUS, SPACING } from '@/src/constants/spacing';
import { focusService } from '@/src/services/focusService';
import { storage, STORAGE_KEYS } from '@/src/services/storage';
import { useAuthStore } from '@/src/store/authStore';
import { useHomeStore } from '@/src/store/homeStore';
import type { Subject } from '@/src/types';
import { router } from 'expo-router';
import { BarChart3, Plus, X } from 'lucide-react-native';
import { useEffect, useState } from 'react';
import {
  Alert,
  Modal,
  Pressable,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View
} from 'react-native';

const DEMO_APP: BlockedApp = {
  id: 1,
  name: 'Instagram',
  category: 'Social',
  icon: '📸',
  blocked: true,
};

const DEFAULT_SUBJECTS: Subject[] = [
  { id: '1', name: 'History', icon: '📜', color: '#8b5cf6' },
  { id: '2', name: 'Geography', icon: '🗺️', color: '#06b6d4' },
  { id: '3', name: 'Polity', icon: '⚖️', color: '#f59e0b' },
  { id: '4', name: 'Economics', icon: '💹', color: '#10b981' },
  { id: '5', name: 'Science', icon: '🔬', color: '#ec4899' },
  { id: '6', name: 'Mathematics', icon: '📐', color: '#3b82f6' },
];

const SUBJECT_ICONS = ['📚', '✏️', '🎓', '📖', '🧮', '🔬', '🌍', '⚖️', '💡', '🎨', '🎵', '💻'];
const SUBJECT_COLORS = [
  '#8b5cf6',
  '#06b6d4',
  '#f59e0b',
  '#10b981',
  '#ec4899',
  '#3b82f6',
  '#ef4444',
  '#f97316',
  '#84cc16',
  '#14b8a6',
  '#6366f1',
  '#a855f7',
];

export default function FocusScreen() {
  const {
    isActive,
    timeLeft,
    totalSeconds,
    cyclesCompleted,
    totalCycles,
    elapsedSeconds,
    coinsEarnedThisSession,
    streak,
    phase,
    subjectStudyData,
    startSession,
    pauseSession,
    resumeSession,
    stopSession,
    tickSecond,
    loadSubjectData,
  } = useFocusStore();

  const { user } = useAuthStore();
  const { refreshHomeData } = useHomeStore();

  const [showUnlock, setShowUnlock] = useState(false);
  const [showSubjectSelect, setShowSubjectSelect] = useState(false);
  const [showAddSubject, setShowAddSubject] = useState(false);
  const [showStats, setShowStats] = useState(false);
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [sessionStarted, setSessionStarted] = useState(false);
  const [customSubjects, setCustomSubjects] = useState<Subject[]>([]);
  const [durationMinutes, setDurationMinutes] = useState(25);
  const [backendSessionId, setBackendSessionId] = useState<string | null>(null);
  const [distractionCount, setDistractionCount] = useState(0);
  const [pauseCountState, setPauseCountState] = useState(0);

  // Add subject form
  const [newSubjectName, setNewSubjectName] = useState('');
  const [selectedIcon, setSelectedIcon] = useState(SUBJECT_ICONS[0]);
  const [selectedColor, setSelectedColor] = useState(SUBJECT_COLORS[0]);

  // Load custom subjects and study data on mount
  useEffect(() => {
    loadCustomSubjects();
    loadSubjectData();
  }, []);

  const loadCustomSubjects = async () => {
    const saved = await storage.load<Subject[]>(STORAGE_KEYS.CUSTOM_SUBJECTS);
    if (saved) {
      setCustomSubjects(saved);
    }
  };

  const saveCustomSubjects = async (subjects: Subject[]) => {
    await storage.save(STORAGE_KEYS.CUSTOM_SUBJECTS, subjects);
    setCustomSubjects(subjects);
  };

  // Show subject selection on mount if not started
  useEffect(() => {
    if (!sessionStarted && phase === 'idle') {
      setShowSubjectSelect(true);
    }
  }, [sessionStarted, phase]);

  // Tick every second when active
  useEffect(() => {
    if (!isActive || !sessionStarted) return;
    const id = setInterval(tickSecond, 1000);
    return () => clearInterval(id);
  }, [isActive, sessionStarted, tickSecond]);

  // Navigate home when all cycles done
  useEffect(() => {
    if (phase === 'done' && backendSessionId && user) {
      // Complete session in backend
      handleCompleteSession();
    }
    return undefined;
  }, [phase]);

  const handleCompleteSession = async () => {
    if (!backendSessionId || !user) return;

    try {
      const actualDuration = Math.floor(elapsedSeconds / 60);
      const { fp, xp } = await focusService.completeFocusSession(
        backendSessionId,
        user.uid,
        actualDuration,
        cyclesCompleted,
        distractionCount,
        pauseCountState
      );

      // Show rewards alert
      Alert.alert(
        '🎉 Session Complete!',
        `Great work! You earned:\n\n+${fp} Focus Points\n+${xp} XP\n\nKeep up the momentum!`,
        [
          {
            text: 'Awesome!',
            onPress: async () => {
              // Refresh home data
              await refreshHomeData(user.uid);
              // Navigate home
              router.push('/' as any);
            },
          },
        ]
      );

      // Clear backend session
      setBackendSessionId(null);
      setDistractionCount(0);
      setPauseCountState(0);
    } catch (error) {
      console.error('Error completing session:', error);
      Alert.alert('Error', 'Failed to save session. Please try again.');
      router.push('/' as any);
    }
  };

  const handleStartWithSubject = async (subject: Subject) => {
    if (!user) {
      Alert.alert('Error', 'Please log in to start a session');
      return;
    }

    try {
      setSelectedSubject(subject);
      setShowSubjectSelect(false);
      setSessionStarted(true);
      
      const durationSeconds = durationMinutes * 60;
      
      // Start session in local store
      startSession(durationSeconds, totalCycles, subject);
      pauseSession(); // Pause immediately so user needs to click play

      // Start session in backend
      const session = await focusService.startFocusSession(
        user.uid,
        durationMinutes,
        totalCycles,
        {
          id: subject.id,
          name: subject.name,
          icon: subject.icon,
          color: subject.color,
        }
      );

      setBackendSessionId(session.id);
      setDistractionCount(0);
      setPauseCountState(0);
    } catch (error) {
      console.error('Error starting session:', error);
      Alert.alert('Error', 'Failed to start session. Please try again.');
      setSessionStarted(false);
      setSelectedSubject(null);
    }
  };

  const handleStop = async () => {
    if (backendSessionId && user) {
      try {
        // Break session in backend (user quit early)
        const actualDuration = Math.floor(elapsedSeconds / 60);
        await focusService.breakFocusSession(backendSessionId, user.uid, actualDuration);
        
        Alert.alert(
          'Session Ended',
          'You ended the session early. No rewards earned.',
          [{ text: 'OK' }]
        );
      } catch (error) {
        console.error('Error breaking session:', error);
      }
    }

    stopSession();
    setSessionStarted(false);
    setSelectedSubject(null);
    setBackendSessionId(null);
    setDistractionCount(0);
    setPauseCountState(0);
    router.push('/' as any);
  };

  const handlePlayPause = async () => {
    if (isActive) {
      pauseSession();
      setPauseCountState((prev) => prev + 1);
      
      // Update pause in backend
      if (backendSessionId) {
        await focusService.pauseFocusSession(backendSessionId);
      }
    } else {
      resumeSession();
      
      // Resume in backend
      if (backendSessionId) {
        await focusService.resumeFocusSession(backendSessionId);
      }
    }
  };

  const handleAddSubject = () => {
    if (!newSubjectName.trim()) {
      // Silently return if name is empty
      return;
    }

    const newSubject: Subject = {
      id: `custom-${Date.now()}`,
      name: newSubjectName.trim(),
      icon: selectedIcon,
      color: selectedColor,
      isCustom: true,
    };

    const updated = [...customSubjects, newSubject];
    saveCustomSubjects(updated);

    setNewSubjectName('');
    setSelectedIcon(SUBJECT_ICONS[0]);
    setSelectedColor(SUBJECT_COLORS[0]);
    setShowAddSubject(false);
  };

  const handleIncreaseDuration = () => {
    setDurationMinutes((prev) => Math.min(prev + 5, 120));
  };

  const handleDecreaseDuration = () => {
    setDurationMinutes((prev) => Math.max(prev - 5, 5));
  };

  const allSubjects = [...DEFAULT_SUBJECTS, ...customSubjects];

  return (
    <View style={styles.screen}>
      {/* Ambient glow */}
      <View style={[styles.glow, isActive ? styles.glowTeal : styles.glowOrange]} />

      {/* Top bar */}
      <View style={styles.topBar}>
        <Pressable style={styles.closeBtn} onPress={handleStop}>
          <X size={20} color={COLORS.textSecondary} />
        </Pressable>
        <View style={styles.topCenter}>
          {selectedSubject && (
            <View style={[styles.subjectBadge, { borderColor: selectedSubject.color }]}>
              <Text style={styles.subjectIcon}>{selectedSubject.icon}</Text>
              <Text style={styles.subjectName}>{selectedSubject.name}</Text>
            </View>
          )}
          <Text style={[styles.modeLabel, { color: isActive ? COLORS.primary : '#f97316' }]}>
            {phase === 'done' 
              ? 'Session Complete!' 
              : isActive 
                ? 'Deep Work Mode' 
                : sessionStarted 
                  ? 'Ready to Start' 
                  : 'Deep Work Mode'}
          </Text>
          <Text style={styles.phaseLabel}>
            Phase {Math.min(cyclesCompleted + 1, totalCycles)} / {totalCycles}
          </Text>
        </View>
        <Pressable style={styles.statsBtn} onPress={() => setShowStats(true)}>
          <BarChart3 size={20} color={COLORS.textSecondary} />
        </Pressable>
      </View>

      {/* Timer ring */}
      <FocusTimer
        timeLeft={timeLeft}
        totalSeconds={totalSeconds}
        isActive={isActive}
        modeLabel=""
        label={phase === 'done' ? 'Complete' : 'Remaining'}
      />

      {/* Ready to start message */}
      {sessionStarted && !isActive && phase === 'focus' && elapsedSeconds === 0 && (
        <View style={styles.readyMessage}>
          <Text style={styles.readyText}>Press Play to Begin</Text>
          <Text style={styles.readyHint}>Your timer is ready</Text>
        </View>
      )}

      {/* Session stats */}
      <View style={styles.statsWrap}>
        <SessionStats
          stats={{
            elapsedSeconds,
            cyclesCompleted,
            totalCycles,
            coinsEarned: coinsEarnedThisSession,
            streak,
          }}
        />
      </View>

      {/* Controls */}
      <SessionControls
        isActive={isActive}
        onPlayPause={handlePlayPause}
        onStop={handleStop}
        onShield={() => setShowUnlock(true)}
        debugLabel="Simulate App Interruption"
        onDebug={() => setShowUnlock(true)}
      />

      {/* Subject Selection Modal */}
      <Modal
        visible={showSubjectSelect}
        transparent
        animationType="slide"
        onRequestClose={() => {
          setShowSubjectSelect(false);
          router.push('/' as any);
        }}
      >
        <View style={styles.modalOverlay}>
          <View style={styles.modalContent}>
            {/* Header */}
            <View style={styles.modalHeader}>
              <Text style={styles.modalTitle}>Start Focus Session</Text>
              <Pressable
                onPress={() => {
                  setShowSubjectSelect(false);
                  router.push('/' as any);
                }}
                hitSlop={8}
              >
                <X size={20} color={COLORS.textSecondary} />
              </Pressable>
            </View>

            {/* Time Adjuster */}
            <View style={styles.timeSection}>
              <TimeAdjuster
                durationMinutes={durationMinutes}
                onIncrease={handleIncreaseDuration}
                onDecrease={handleDecreaseDuration}
              />
            </View>

            <Text style={styles.modalSubtitle}>Choose a subject to focus on</Text>

            {/* Subject Grid */}
            <ScrollView
              style={styles.subjectScroll}
              contentContainerStyle={styles.subjectGrid}
              showsVerticalScrollIndicator={false}
            >
              {allSubjects.map((subject) => (
                <Pressable
                  key={subject.id}
                  style={({ pressed }) => [styles.subjectCard, pressed && { opacity: 0.7 }]}
                  onPress={() => handleStartWithSubject(subject)}
                >
                  <View
                    style={[
                      styles.subjectIconBox,
                      { backgroundColor: `${subject.color}20` },
                    ]}
                  >
                    <Text style={styles.subjectCardIcon}>{subject.icon}</Text>
                  </View>
                  <Text style={styles.subjectCardName}>{subject.name}</Text>
                  {subject.isCustom && <Text style={styles.customBadge}>Custom</Text>}
                  <View style={[styles.startIndicator, { backgroundColor: subject.color }]}>
                    <Text style={styles.startText}>Start</Text>
                  </View>
                </Pressable>
              ))}

              {/* Add Subject Card */}
              <Pressable
                style={({ pressed }) => [
                  styles.subjectCard,
                  styles.addCard,
                  pressed && { opacity: 0.7 },
                ]}
                onPress={() => setShowAddSubject(true)}
              >
                <View style={styles.addIconBox}>
                  <Plus size={32} color={COLORS.primary} />
                </View>
                <Text style={styles.addCardText}>Add Subject</Text>
              </Pressable>
            </ScrollView>
          </View>
        </View>
      </Modal>

      {/* Add Subject Modal */}
      <Modal
        visible={showAddSubject}
        transparent
        animationType="fade"
        onRequestClose={() => setShowAddSubject(false)}
      >
        <View style={styles.modalOverlay}>
          <View style={[styles.modalContent, styles.addSubjectModal]}>
            <View style={styles.modalHeader}>
              <Text style={styles.modalTitle}>Add Custom Subject</Text>
              <Pressable onPress={() => setShowAddSubject(false)} hitSlop={8}>
                <X size={20} color={COLORS.textSecondary} />
              </Pressable>
            </View>

            <View style={styles.formSection}>
              <Text style={styles.formLabel}>Subject Name</Text>
              <TextInput
                style={styles.input}
                value={newSubjectName}
                onChangeText={setNewSubjectName}
                placeholder="e.g., Biology, Physics, etc."
                placeholderTextColor={COLORS.textSecondary}
                maxLength={20}
              />
            </View>

            <View style={styles.formSection}>
              <Text style={styles.formLabel}>Choose Icon</Text>
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                contentContainerStyle={styles.iconGrid}
              >
                {SUBJECT_ICONS.map((icon) => (
                  <Pressable
                    key={icon}
                    style={[
                      styles.iconOption,
                      selectedIcon === icon && styles.iconOptionSelected,
                    ]}
                    onPress={() => setSelectedIcon(icon)}
                  >
                    <Text style={styles.iconOptionText}>{icon}</Text>
                  </Pressable>
                ))}
              </ScrollView>
            </View>

            <View style={styles.formSection}>
              <Text style={styles.formLabel}>Choose Color</Text>
              <View style={styles.colorGrid}>
                {SUBJECT_COLORS.map((color) => (
                  <Pressable
                    key={color}
                    style={[
                      styles.colorOption,
                      { backgroundColor: color },
                      selectedColor === color && styles.colorOptionSelected,
                    ]}
                    onPress={() => setSelectedColor(color)}
                  />
                ))}
              </View>
            </View>

            <Pressable style={styles.addButton} onPress={handleAddSubject}>
              <Text style={styles.addButtonText}>Add Subject</Text>
            </Pressable>
          </View>
        </View>
      </Modal>

      {/* Stats Modal */}
      <Modal
        visible={showStats}
        transparent
        animationType="slide"
        onRequestClose={() => setShowStats(false)}
      >
        <View style={styles.modalOverlay}>
          <View style={styles.modalContent}>
            <View style={styles.modalHeader}>
              <Text style={styles.modalTitle}>Study Statistics</Text>
              <Pressable onPress={() => setShowStats(false)} hitSlop={8}>
                <X size={20} color={COLORS.textSecondary} />
              </Pressable>
            </View>
            <SubjectStats subjectData={subjectStudyData} />
          </View>
        </View>
      </Modal>

      {/* Unlock penalty dialog */}
      <UnlockDialog
        visible={showUnlock}
        app={DEMO_APP}
        onReturnToFocus={() => {
          setShowUnlock(false);
          // Record distraction in backend
          if (backendSessionId) {
            setDistractionCount((prev) => prev + 1);
            focusService.recordDistraction(backendSessionId);
          }
        }}
        onConfirmUnlock={() => {
          setShowUnlock(false);
          handleStop();
        }}
        onDismiss={() => setShowUnlock(false)}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  screen: {
    flex: 1,
    backgroundColor: COLORS.background,
    alignItems: 'center',
  },
  glow: {
    position: 'absolute',
    width: 280,
    height: 280,
    borderRadius: 140,
    top: '25%',
    alignSelf: 'center',
    opacity: 0.12,
  },
  glowTeal: { backgroundColor: COLORS.primary },
  glowOrange: { backgroundColor: '#f97316' },

  topBar: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    width: '100%',
    paddingHorizontal: 20,
    paddingTop: 52,
    marginBottom: 8,
  },
  closeBtn: {
    width: 40,
    height: 40,
    backgroundColor: COLORS.surface,
    borderWidth: 1,
    borderColor: COLORS.border,
    borderRadius: 20,
    alignItems: 'center',
    justifyContent: 'center',
  },
  statsBtn: {
    width: 40,
    height: 40,
    backgroundColor: COLORS.surface,
    borderWidth: 1,
    borderColor: COLORS.border,
    borderRadius: 20,
    alignItems: 'center',
    justifyContent: 'center',
  },
  topCenter: { alignItems: 'center', gap: 4 },
  subjectBadge: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 6,
    backgroundColor: COLORS.surface,
    borderWidth: 2,
    borderRadius: 16,
    paddingHorizontal: 12,
    paddingVertical: 6,
    marginBottom: 4,
  },
  subjectIcon: {
    fontSize: 14,
  },
