// Route: "/study-history" → Study History Screen
import { useFocusStore } from '@/src/components/focus';
import { COLORS } from '@/src/constants/colors';
import { RADIUS, SPACING } from '@/src/constants/spacing';
import type { SubjectStudyData } from '@/src/types';
import { router } from 'expo-router';
import { ArrowLeft, BookOpen, ChevronRight, Clock, TrendingUp } from 'lucide-react-native';
import { useEffect, useState } from 'react';
import { Pressable, ScrollView, StyleSheet, Text, View } from 'react-native';

export default function StudyHistoryScreen() {
  const { subjectStudyData, loadSubjectData } = useFocusStore();
  const [subjects, setSubjects] = useState<SubjectStudyData[]>([]);

  useEffect(() => {
    loadSubjectData();
  }, []);

  useEffect(() => {
    const subjectList = Object.values(subjectStudyData).sort(
      (a, b) => b.totalFocusTime - a.totalFocusTime
    );
    setSubjects(subjectList);
  }, [subjectStudyData]);

  const formatTime = (seconds: number) => {
    const hours = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    if (hours > 0) {
      return `${hours}h ${mins}m`;
    }
    return `${mins}m`;
  };

  const formatDate = (timestamp?: number) => {
    if (!timestamp) return 'Never';
    const date = new Date(timestamp);
    const now = new Date();
    const diffDays = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24));
    
    if (diffDays === 0) return 'Today';
    if (diffDays === 1) return 'Yesterday';
    if (diffDays < 7) return `${diffDays} days ago`;
    return date.toLocaleDateString();
  };

  const totalStudyTime = subjects.reduce((sum, s) => sum + s.totalFocusTime, 0);
  const totalSessions = subjects.reduce((sum, s) => sum + s.totalSessions, 0);

  return (
    <View style={styles.screen}>
      {/* Header */}
      <View style={styles.header}>
        <Pressable style={styles.backBtn} onPress={() => router.back()}>
          <ArrowLeft size={20} color={COLORS.text} />
        </Pressable>
        <Text style={styles.headerTitle}>Study History</Text>
        <View style={styles.spacer} />
      </View>

      <ScrollView
        style={styles.scrollView}
        contentContainerStyle={styles.container}
        showsVerticalScrollIndicator={false}
      >
        {/* Overall Stats */}
        <View style={styles.overallCard}>
          <Text style={styles.overallTitle}>Overall Progress</Text>
          <View style={styles.overallStats}>
            <View style={styles.overallStat}>
              <Clock size={24} color={COLORS.primary} />
              <Text style={styles.overallValue}>{formatTime(totalStudyTime)}</Text>
              <Text style={styles.overallLabel}>Total Time</Text>
            </View>
            <View style={styles.divider} />
            <View style={styles.overallStat}>
              <BookOpen size={24} color={COLORS.primary} />
              <Text style={styles.overallValue}>{totalSessions}</Text>
              <Text style={styles.overallLabel}>Sessions</Text>
            </View>
            <View style={styles.divider} />
            <View style={styles.overallStat}>
              <TrendingUp size={24} color={COLORS.primary} />
              <Text style={styles.overallValue}>{subjects.length}</Text>
              <Text style={styles.overallLabel}>Subjects</Text>
            </View>
          </View>
        </View>

        {/* Subject List */}
        {subjects.length === 0 ? (
          <View style={styles.emptyContainer}>
            <Text style={styles.emptyIcon}>📚</Text>
            <Text style={styles.emptyText}>No study history yet</Text>
            <Text style={styles.emptyHint}>
              Start a focus session to track your progress
            </Text>
            <Pressable
              style={styles.startButton}
              onPress={() => router.push('/focus' as any)}
            >
              <Text style={styles.startButtonText}>Start Studying</Text>
            </Pressable>
          </View>
        ) : (
          <>
            <Text style={styles.sectionTitle}>Subjects</Text>
            {subjects.map((subject, index) => (
              <Pressable
                key={subject.subjectId}
                style={styles.subjectCard}
                onPress={() => router.push(`/subject-detail?subjectId=${subject.subjectId}` as any)}
              >
                <View style={styles.subjectHeader}>
                  <View style={styles.subjectRank}>
                    <Text style={styles.rankText}>#{index + 1}</Text>
                  </View>
                  <View style={styles.subjectInfo}>
                    <Text style={styles.subjectName}>{subject.subjectName}</Text>
                    <Text style={styles.lastStudied}>
                      Last studied: {formatDate(subject.lastStudied)}
                    </Text>
                  </View>
                  <ChevronRight size={20} color={COLORS.border} />
                </View>
                <View style={styles.subjectStats}>
                  <View style={styles.stat}>
                    <Clock size={16} color={COLORS.primary} />
                    <Text style={styles.statValue}>{formatTime(subject.totalFocusTime)}</Text>
                  </View>
                  <View style={styles.stat}>
                    <BookOpen size={16} color={COLORS.primary} />
                    <Text style={styles.statValue}>{subject.totalSessions} sessions</Text>
                  </View>
                </View>
              </Pressable>
            ))}
          </>
        )}
      </ScrollView>
    </View>
  );
}

