  /**
   * Get user stats
   */
  async getUserStats(userId: string): Promise<UserStats> {
    try {
      const docRef = doc(db, 'userStats', userId);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const data = docSnap.data();
        return {
          ...data,
          createdAt: data.createdAt?.toDate() || new Date(),
          updatedAt: data.updatedAt?.toDate() || new Date(),
          streakUpdatedAt: data.streakUpdatedAt?.toDate() || new Date(),
        } as UserStats;
      }

      // Initialize if doesn't exist
      return await this.initializeUserStats(userId);
    } catch (error) {
      console.error('Error getting user stats:', error);
      // Fallback to local storage
      const local = await storage.load<UserStats>(STORAGE_KEYS.USER_PROFILE);
      if (local) return local;
      throw error;
    }
  }

  /**
   * Initialize user stats (first time)
   */
  async initializeUserStats(userId: string): Promise<UserStats> {
    const initialStats: UserStats = {
      userId,
      totalFocusPoints: 100,        // Start with 100 FP
      currentFocusPoints: 100,      // Start with 100 FP
      currentLevel: 1,
      totalXP: 0,
      xpToNextLevel: 100,
      levelProgress: 0,
      totalSessions: 0,
      totalMinutes: 0,
      totalDeepWorkHours: 0,
      averageSessionLength: 0,
