      bestStreak: 0,
      lastSessionDate: '',
      streakUpdatedAt: new Date(),
      achievementLevel: 'Novice I',
      achievementName: 'Beginner',
      achievementTier: 1,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    try {
      await setDoc(doc(db, 'userStats', userId), {
        ...initialStats,
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
