  /**
   * Update user stats
   */
  async updateUserStats(userId: string, updates: Partial<UserStats>): Promise<void> {
    try {
      await updateDoc(doc(db, 'userStats', userId), {
        ...updates,
        updatedAt: serverTimestamp(),
      });

      // Update local storage
      const current = await this.getUserStats(userId);
      await storage.save(STORAGE_KEYS.USER_PROFILE, { ...current, ...updates });
