  /**
   * Award Focus Points and XP
   */
  async awardRewards(userId: string, focusPoints: number, xp: number): Promise<void> {
    try {
      const stats = await this.getUserStats(userId);

      // Calculate new totals
      const newTotalFP = stats.totalFocusPoints + focusPoints;
      const newCurrentFP = stats.currentFocusPoints + focusPoints;
      const newTotalXP = stats.totalXP + xp;

      // Calculate new level
      const levelInfo = calculateLevel(newTotalXP);
      const achievement = getAchievementTier(levelInfo.level);

      // Update stats
      await this.updateUserStats(userId, {
        totalFocusPoints: newTotalFP,
        currentFocusPoints: newCurrentFP,
        totalXP: newTotalXP,
        currentLevel: levelInfo.level,
        xpToNextLevel: levelInfo.xpToNextLevel,
        levelProgress: levelInfo.progress,
        achievementLevel: achievement.level,
        achievementName: achievement.name,
        achievementTier: achievement.tier,
      });
    } catch (error) {
      console.error('Error awarding rewards:', error);
      throw error;
    }
  }

  /**
   * Update streak after completing a session
   */
  async updateStreak(userId: string): Promise<void> {
    try {
      const stats = await this.getUserStats(userId);
      const today = this.getTodayDateString();
      const yesterday = this.getYesterdayDateString();

      let newStreak = stats.currentStreak;

      // If last session was yesterday, increment streak
      if (stats.lastSessionDate === yesterday) {
        newStreak = stats.currentStreak + 1;
      }
      // If last session was today, keep streak
      else if (stats.lastSessionDate === today) {
        newStreak = stats.currentStreak;
      }
      // Otherwise, reset to 1
      else {
        newStreak = 1;
      }

      // Update best streak if needed
      const newBestStreak = Math.max(stats.bestStreak, newStreak);

      await this.updateUserStats(userId, {
        currentStreak: newStreak,
        bestStreak: newBestStreak,
        lastSessionDate: today,
        streakUpdatedAt: new Date(),
      });
    } catch (error) {
      console.error('Error updating streak:', error);
      throw error;
    }
  }

  /**
   * Record session completion
   */
  async recordSessionCompletion(
    userId: string,
    durationMinutes: number,
    fpEarned: number,
    xpEarned: number
  ): Promise<void> {
    try {
      const stats = await this.getUserStats(userId);

      // Calculate new totals
      const newTotalSessions = stats.totalSessions + 1;
      const newTotalMinutes = stats.totalMinutes + durationMinutes;
      const newAverageLength = Math.round(newTotalMinutes / newTotalSessions);

      // Check if deep work (90+ minutes)
      const isDeepWork = durationMinutes >= 90;
      const newDeepWorkHours = isDeepWork
        ? stats.totalDeepWorkHours + durationMinutes / 60
        : stats.totalDeepWorkHours;

      // Update stats
      await this.updateUserStats(userId, {
        totalSessions: newTotalSessions,
        totalMinutes: newTotalMinutes,
        totalDeepWorkHours: newDeepWorkHours,
        averageSessionLength: newAverageLength,
      });

      // Award rewards
      await this.awardRewards(userId, fpEarned, xpEarned);

      // Update streak
      await this.updateStreak(userId);

      // Update daily challenges
      await this.updateChallengeProgress(userId, 'session', 1);
      await this.updateChallengeProgress(userId, 'time', durationMinutes);
      if (isDeepWork) {
        await this.updateChallengeProgress(userId, 'deep-work', 1);
      }
    } catch (error) {
      console.error('Error recording session completion:', error);
      throw error;
    }
  }

