  /**
   * Update pet after session
   */
  async feedPet(userId: string): Promise<void> {
    try {
      const pet = await this.getPetStatus(userId);
      const stats = await this.getUserStats(userId);

      // Calculate new mood based on streak
      let mood: 'optimal' | 'happy' | 'tired' | 'sad' = 'happy';
      if (stats.currentStreak >= 7) mood = 'optimal';
      else if (stats.currentStreak >= 3) mood = 'happy';
      else mood = 'tired';

      // Calculate loyalty based on streak
      const loyalty = Math.min(100, 50 + stats.currentStreak * 3);

      // Health is always 100 after feeding
      const health = 100;

      await updateDoc(doc(db, 'petStatus', userId), {
        mood,
        loyalty,
        health,
        energy: 100,
        lastFed: serverTimestamp(),
        level: stats.currentLevel,
        updatedAt: serverTimestamp(),
      });
    } catch (error) {
      console.error('Error feeding pet:', error);
      throw error;
    }
  }

  /**
   * Get daily challenges for today
   */
  async getDailyChallenges(userId: string): Promise<DailyChallenge[]> {
    try {
      const today = this.getTodayDateString();

      const q = query(
        collection(db, 'dailyChallenges'),
        where('userId', '==', userId),
        where('date', '==', today)
      );

      const snapshot = await getDocs(q);

      if (!snapshot.empty) {
        return snapshot.docs.map((doc) => ({
          id: doc.id,
          ...doc.data(),
          createdAt: doc.data().createdAt?.toDate() || new Date(),
          completedAt: doc.data().completedAt?.toDate(),
          expiresAt: doc.data().expiresAt?.toDate() || new Date(),
        })) as DailyChallenge[];
      }

      // Generate new challenges for today
      return await this.generateDailyChallenges(userId);
    } catch (error) {
      console.error('Error getting daily challenges:', error);
      return [];
    }
  }

  /**
   * Generate daily challenges
   */
  async generateDailyChallenges(userId: string): Promise<DailyChallenge[]> {
    try {
      const stats = await this.getUserStats(userId);
      const today = this.getTodayDateString();
      const endOfDay = this.getEndOfDay();

      const challenges: Omit<DailyChallenge, 'id'>[] = [
        // Challenge 1: Complete sessions (scales with level)
        {
          userId,
          title: stats.currentLevel < 20 ? 'Focus Starter' : 'Focus Marathon',
          description:
            stats.currentLevel < 20
              ? 'Complete 2 focus sessions'
              : 'Complete 4 focus sessions',
          type: 'session',
          progress: 0,
          total: stats.currentLevel < 20 ? 2 : 4,
          unit: 'sessions',
          completed: false,
          rewardFP: stats.currentLevel < 20 ? 30 : 60,
          rewardXP: stats.currentLevel < 20 ? 50 : 100,
          difficulty: stats.currentLevel < 20 ? 'easy' : 'medium',
          category: 'consistency',
          date: today,
          createdAt: new Date(),
          expiresAt: endOfDay,
        },
        // Challenge 2: Accumulate time
        {
          userId,
          title: 'Time Investment',
          description: `Focus for ${stats.currentLevel < 30 ? '60' : '120'} minutes total`,
          type: 'time',
          progress: 0,
          total: stats.currentLevel < 30 ? 60 : 120,
          unit: 'min',
          completed: false,
          rewardFP: stats.currentLevel < 30 ? 40 : 80,
          rewardXP: stats.currentLevel < 30 ? 60 : 120,
          difficulty: stats.currentLevel < 30 ? 'medium' : 'hard',
          category: 'dedication',
          date: today,
          createdAt: new Date(),
          expiresAt: endOfDay,
        },
        // Challenge 3: Deep work (if level 10+)
        ...(stats.currentLevel >= 10
          ? [
              {
                userId,
                title: 'Deep Work Protocol',
                description: 'Complete one 90-minute deep work session',
                type: 'deep-work' as const,
                progress: 0,
                total: 1,
                unit: 'session',
                completed: false,
                rewardFP: 100,
                rewardXP: 150,
                difficulty: 'hard' as const,
                category: 'mastery',
                date: today,
                createdAt: new Date(),
                expiresAt: endOfDay,
              },
            ]
          : []),
      ];

      // Save to Firestore
      const savedChallenges: DailyChallenge[] = [];
      for (const challenge of challenges) {
        const docRef = await addDoc(collection(db, 'dailyChallenges'), {
          ...challenge,
          createdAt: serverTimestamp(),
          expiresAt: Timestamp.fromDate(endOfDay),
        });
        savedChallenges.push({ id: docRef.id, ...challenge });
      }

      return savedChallenges;
    } catch (error) {
      console.error('Error generating daily challenges:', error);
      return [];
    }
  }

  /**
   * Update challenge progress
   */
  async updateChallengeProgress(
    userId: string,
    type: string,
    amount: number
  ): Promise<void> {
    try {
      const challenges = await this.getDailyChallenges(userId);

      for (const challenge of challenges) {
        if (challenge.type === type && !challenge.completed) {
          const newProgress = challenge.progress + amount;
          const completed = newProgress >= challenge.total;

          await updateDoc(doc(db, 'dailyChallenges', challenge.id), {
            progress: Math.min(newProgress, challenge.total),
            completed,
            ...(completed && { completedAt: serverTimestamp() }),
          });

          // Award rewards if completed
          if (completed && !challenge.completed) {
            await this.awardRewards(userId, challenge.rewardFP, challenge.rewardXP);
          }
        }
      }
    } catch (error) {
      console.error('Error updating challenge progress:', error);
    }
  }

  /**
   * Get challenge history
   */
  async getChallengeHistory(userId: string, days: number = 7): Promise<ChallengeHistory[]> {
    try {
      const q = query(
        collection(db, 'challengeHistory'),
        where('userId', '==', userId),
        orderBy('date', 'desc'),
        limit(days)
      );

      const snapshot = await getDocs(q);

      return snapshot.docs.map((doc) => ({
        id: doc.id,
        ...doc.data(),
        createdAt: doc.data().createdAt?.toDate() || new Date(),
      })) as ChallengeHistory[];
    } catch (error) {
      console.error('Error getting challenge history:', error);
      return [];
    }
  }

  /**
   * Save today's challenges to history (called at end of day)
   */
  async saveChallengeHistory(userId: string): Promise<void> {
    try {
      const challenges = await this.getDailyChallenges(userId);
      const today = this.getTodayDateString();

      const completedCount = challenges.filter((c) => c.completed).length;
      const fpEarned = challenges
        .filter((c) => c.completed)
        .reduce((sum, c) => sum + c.rewardFP, 0);
      const xpEarned = challenges
        .filter((c) => c.completed)
        .reduce((sum, c) => sum + c.rewardXP, 0);

      await addDoc(collection(db, 'challengeHistory'), {
        userId,
        date: today,
        challengesCompleted: completedCount,
        totalChallenges: challenges.length,
        fpEarned,
        xpEarned,
        challenges,
        createdAt: serverTimestamp(),
      });
    } catch (error) {
      console.error('Error saving challenge history:', error);
    }
  }

  // ═══════════════════════════════════════════════════════════
  // HELPER METHODS
  // ═══════════════════════════════════════════════════════════

  private getTodayDateString(): string {
    return new Date().toISOString().split('T')[0];
  }

  private getYesterdayDateString(): string {
    const yesterday = new Date();
    yesterday.setDate(yesterday.getDate() - 1);
    return yesterday.toISOString().split('T')[0];
  }

  private getEndOfDay(): Date {
    const end = new Date();
    end.setHours(23, 59, 59, 999);
    return end;
  }

  private isTodayDone(lastSessionDate: string): boolean {
    return lastSessionDate === this.getTodayDateString();
  }
}

