/**
 * Get all installed apps on the device
 * For Expo Go: Returns common student apps
 * For Dev Build: Uses react-native-launcher-kit to detect installed apps
 */
export async function getAllInstalledApps(): Promise<InstalledApp[]> {
  try {
    // Try to use react-native-launcher-kit on Android (only works with dev builds)
    if (Platform.OS === 'android') {
      try {
        // Dynamic import to avoid errors in Expo Go
        const { InstalledApps } = require('react-native-launcher-kit');
        
        console.log('🔍 Getting ALL installed apps from device...');
        
        const installedApps = await InstalledApps.getApps();
        
        console.log(`📱 Found ${installedApps.length} installed apps on device`);
        
        // Get known student apps
        const knownApps = getCommonStudentApps();
        
        // Filter installed apps to show only known distracting apps
        const installedKnownApps = knownApps.filter(knownApp => 
          installedApps.some((installed: any) => 
            installed.packageName === knownApp.packageName
          )
        );
        
        console.log(`✅ Found ${installedKnownApps.length} known student apps installed`);
        
        // Return only the known apps that are actually installed
        return installedKnownApps.length > 0 ? installedKnownApps : knownApps;
      } catch (nativeError) {
        // Native module not available (Expo Go or linking issue)
        console.log('ℹ️ Native module not available, using fallback app list');
        console.log('💡 To detect actual installed apps, create a development build');
        return getCommonStudentApps();
      }
    }
    
    // Fallback for iOS - return common apps
    return getCommonStudentApps();
  } catch (error) {
    console.error('Error getting installed apps:', error);
    // Fallback to common apps
    return getCommonStudentApps();
  }
}

