      ]);

      // Get user info from auth
      const userDoc = await getDoc(doc(db, 'users', userId));
      const userData = userDoc.data();

      const unlockedCount = achievements.filter((a) => a.unlocked).length;

      return {
        userId,
        username: userData?.username || 'Student',
        email: userData?.email || '',
        avatar: userData?.avatar || '',
        level: userStats.currentLevel,
        focusPoints: userStats.currentFocusPoints,
        totalSessions: userStats.totalSessions,
        totalHours: Math.round(userStats.totalMinutes / 60),
        currentStreak: userStats.currentStreak,
        totalAchievements: ACHIEVEMENT_DEFINITIONS.length,
        unlockedAchievements: unlockedCount,
        joinedAt: userStats.createdAt,
        lastActive: userStats.updatedAt,
      };
    } catch (error) {
      console.error('Error getting user profile:', error);
      throw error;
    }
  }

  /**
   * Get user achievements
   */
  async getUserAchievements(userId: string): Promise<Achievement[]> {
    try {
      // Get user's unlocked achievements
      const docRef = doc(db, 'achievements', userId);
      const docSnap = await getDoc(docRef);

      const unlockedIds: Record<string, Date> = {};
      if (docSnap.exists()) {
        const data = docSnap.data();
        Object.entries(data.unlocked || {}).forEach(([id, timestamp]: [string, any]) => {
          unlockedIds[id] = timestamp?.toDate() || new Date();
        });
      }

      // Get user stats for progress calculation
      const [userStats, focusStats, blockingStats, sessions] = await Promise.all([
        homeService.getUserStats(userId),
        focusService.getFocusStats(userId),
        blockingService.getBlockingStats(userId),
        focusService.getUserSessions(userId, 100),
      ]);

      // Map achievements with progress
      const achievements: Achievement[] = ACHIEVEMENT_DEFINITIONS.map((def) => {
        const unlocked = !!unlockedIds[def.id];
        const currentValue = this.getCurrentValue(def, userStats, focusStats, blockingStats, sessions);
        const progress = unlocked ? 100 : Math.min(100, Math.round((currentValue / def.requirement) * 100));

        return {
          ...def,
          unlocked,
          unlockedAt: unlockedIds[def.id],
          progress,
          currentValue,
        };
      });

      // Check and unlock new achievements
      await this.checkAndUnlockAchievements(userId, achievements);

      return achievements;
    } catch (error) {
      console.error('Error getting user achievements:', error);
      return [];
    }
  }

  /**
   * Get current value for achievement progress
   */
  private getCurrentValue(
    achievement: Omit<Achievement, 'unlocked' | 'unlockedAt' | 'progress' | 'currentValue'>,
    userStats: any,
    focusStats: any,
    blockingStats: any,
    sessions: any[]
  ): number {
    switch (achievement.id) {
      case 'first-session':
      case 'sessions-10':
      case 'sessions-50':
      case 'sessions-100':
      case 'sessions-500':
        return userStats.totalSessions;

      case 'streak-3':
      case 'streak-7':
      case 'streak-30':
      case 'streak-100':
        return userStats.currentStreak;

      case 'level-10':
      case 'level-50':
      case 'level-100':
        return userStats.currentLevel;

      case 'deep-work-first':
      case 'deep-work-10':
      case 'deep-work-50':
        return focusStats.totalDeepWorkSessions;

      case 'blocking-master':
        return blockingStats.completedSessions;

      case 'early-bird':
        return sessions.filter((s) => new Date(s.startTime).getHours() < 8).length;

      case 'night-owl':
        return sessions.filter((s) => new Date(s.startTime).getHours() >= 22).length;

      case 'perfect-week':
        // Check last 7 days for 90+ focus score
        const weekAgo = new Date();
        weekAgo.setDate(weekAgo.getDate() - 7);
        const weekSessions = sessions.filter(
          (s) => new Date(s.startTime) >= weekAgo && s.focusScore >= 90
        );
        return weekSessions.length;

      case 'perfect-score':
        return sessions.filter((s) => s.focusScore === 100).length;

      default:
        return 0;
    }
  }

  /**
   * Check and unlock achievements
   */
  private async checkAndUnlockAchievements(
    userId: string,
    achievements: Achievement[]
  ): Promise<void> {
    try {
      const toUnlock = achievements.filter(
        (a) => !a.unlocked && a.currentValue >= a.requirement
      );

      if (toUnlock.length === 0) return;

      const docRef = doc(db, 'achievements', userId);
      const docSnap = await getDoc(docRef);

      const unlocked: Record<string, any> = docSnap.exists() ? docSnap.data().unlocked || {} : {};

      toUnlock.forEach((achievement) => {
        unlocked[achievement.id] = serverTimestamp();
      });

      await setDoc(docRef, { userId, unlocked, updatedAt: serverTimestamp() }, { merge: true });

      // Award bonus FP for unlocking achievements
      const bonusFP = toUnlock.length * 50; // 50 FP per achievement
      if (bonusFP > 0) {
        await homeService.awardRewards(userId, bonusFP, 0);
      }
    } catch (error) {
      console.error('Error unlocking achievements:', error);
    }
  }

